('component_event_if_coupon', '示例：事件触发新客领券', '组件教学 / 拉新转化 示例，展示 EVENT_TRIGGER,IF_CONDITION,COUPON 的配置和组合方式。', '拉新转化', '{"nodes":[{"id":"start","type":"START","name":"开始","category":"流程控制","x":400,"y":0,"config":{"nextNodeId":"event"},"bizConfig":{"nextNodeId":"event"}},{"id":"event","type":"EVENT_TRIGGER","name":"订单完成事件","category":"行为策略","x":400,"y":140,"config":{"eventCode":"ORDER_COMPLETE","nextNodeId":"if_new"},"bizConfig":{"eventCode":"ORDER_COMPLETE","nextNodeId":"if_new"}},{"id":"if_new","type":"IF_CONDITION","name":"是否目标用户","category":"逻辑分支","x":400,"y":280,"config":{"rules":[{"field":"isNewUser","operator":"EQ","value":"true"}],"successNodeId":"coupon","failNodeId":"end"},"bizConfig":{"rules":[{"field":"isNewUser","operator":"EQ","value":"true"}],"successNodeId":"coupon","failNodeId":"end"}},{"id":"coupon","type":"COUPON","name":"发放权益券","category":"权益发放","x":180,"y":420,"config":{"couponTypeKey":"flight_coupon","nextNodeId":"end"},"bizConfig":{"couponTypeKey":"flight_coupon","nextNodeId":"end"}},{"id":"end","type":"END","name":"结束","category":"流程控制","x":400,"y":560,"config":{},"bizConfig":{}}]}', NULL, 1, 0, 'example-seed', NOW(), '组件教学', '拉新转化', '入门', 'EVENT_TRIGGER,IF_CONDITION,COUPON', 1, 1),
('component_mq_validate_route', '示例：MQ 消息校验后路由', '组件教学 / 消息触发 示例，展示 MQ_TRIGGER,IF_CONDITION,SEND_MQ 的配置和组合方式。', '消息触发', '{"nodes":[{"id":"start","type":"START","name":"开始","category":"流程控制","x":400,"y":0,"config":{"nextNodeId":"mq"},"bizConfig":{"nextNodeId":"mq"}},{"id":"mq","type":"MQ_TRIGGER","name":"订单状态 MQ","category":"行为策略","x":400,"y":140,"config":{"topicKey":"CANVAS_MQ_TRIGGER","validateResult":true,"validateRules":[{"field":"orderStatus","operator":"EQ","value":"PAID"}],"nextNodeId":"if_paid"},"bizConfig":{"topicKey":"CANVAS_MQ_TRIGGER","validateResult":true,"validateRules":[{"field":"orderStatus","operator":"EQ","value":"PAID"}],"nextNodeId":"if_paid"}},{"id":"if_paid","type":"IF_CONDITION","name":"是否支付成功","category":"逻辑分支","x":400,"y":280,"config":{"rules":[{"field":"orderStatus","operator":"EQ","value":"PAID"}],"successNodeId":"send_mq","failNodeId":"end"},"bizConfig":{"rules":[{"field":"orderStatus","operator":"EQ","value":"PAID"}],"successNodeId":"send_mq","failNodeId":"end"}},{"id":"send_mq","type":"SEND_MQ","name":"通知下游系统","category":"其他","x":180,"y":420,"config":{"messageCodeKey":"order_paid_notice","nextNodeId":"end"},"bizConfig":{"messageCodeKey":"order_paid_notice","nextNodeId":"end"}},{"id":"end","type":"END","name":"结束","category":"流程控制","x":400,"y":560,"config":{},"bizConfig":{}}]}', NULL, 1, 0, 'example-seed', NOW(), '组件教学', '消息触发', '入门', 'MQ_TRIGGER,IF_CONDITION,SEND_MQ', 2, 1),
('component_scheduled_audience_push', '示例：定时人群 Push', '组件教学 / 定时运营 示例，展示 SCHEDULED_TRIGGER,TAGGER,REACH_PLATFORM 的配置和组合方式。', '定时运营', '{"nodes":[{"id":"start","type":"START","name":"开始","category":"流程控制","x":400,"y":0,"config":{"nextNodeId":"schedule"},"bizConfig":{"nextNodeId":"schedule"}},{"id":"schedule","type":"SCHEDULED_TRIGGER","name":"每日定时触发","category":"行为策略","x":400,"y":140,"config":{"scheduleType":"CRON","cronExpression":"0 0 9 * * ?","timezone":"Asia/Shanghai","nextNodeId":"audience"},"bizConfig":{"scheduleType":"CRON","cronExpression":"0 0 9 * * ?","timezone":"Asia/Shanghai","nextNodeId":"audience"}},{"id":"audience","type":"TAGGER","name":"判断目标人群","category":"人群圈选","x":400,"y":280,"config":{"mode":"audience","audienceId":90001,"hitNextNodeId":"reach","missNextNodeId":"end"},"bizConfig":{"mode":"audience","audienceId":90001,"hitNextNodeId":"reach","missNextNodeId":"end"}},{"id":"reach","type":"REACH_PLATFORM","name":"发送营销触达","category":"用户触达","x":180,"y":420,"config":{"serviceSceneKey":"promo_push","nextNodeId":"end"},"bizConfig":{"serviceSceneKey":"promo_push","nextNodeId":"end"}},{"id":"end","type":"END","name":"结束","category":"流程控制","x":400,"y":560,"config":{},"bizConfig":{}}]}', NULL, 1, 0, 'example-seed', NOW(), '组件教学', '定时运营', '入门', 'SCHEDULED_TRIGGER,TAGGER,REACH_PLATFORM', 3, 1),
('component_direct_call_return', '示例：直调查询并同步返回', '组件教学 / 直调返回 示例，展示 DIRECT_CALL,API_CALL,DIRECT_RETURN 的配置和组合方式。', '直调返回', '{"nodes":[{"id":"start","type":"START","name":"开始","category":"流程控制","x":400,"y":0,"config":{"nextNodeId":"direct"},"bizConfig":{"nextNodeId":"direct"}},{"id":"direct","type":"DIRECT_CALL","name":"业务直调触发","category":"行为策略","x":400,"y":140,"config":{"eventCode":"ORDER_COMPLETE","nextNodeId":"api"},"bizConfig":{"eventCode":"ORDER_COMPLETE","nextNodeId":"api"}},{"id":"api","type":"API_CALL","name":"查询用户信息","category":"其他","x":400,"y":280,"config":{"apiKey":"query_user_info","outputPrefix":"user","nextNodeId":"return"},"bizConfig":{"apiKey":"query_user_info","outputPrefix":"user","nextNodeId":"return"}},{"id":"return","type":"DIRECT_RETURN","name":"同步返回结果","category":"用户触达","x":400,"y":420,"config":{"buildType":"CUSTOM","data":[{"key":"userLevel","value":"${user.level}"}]},"bizConfig":{"buildType":"CUSTOM","data":[{"key":"userLevel","value":"${user.level}"}]}}]}', NULL, 1, 0, 'example-seed', NOW(), '组件教学', '直调返回', '进阶', 'DIRECT_CALL,API_CALL,DIRECT_RETURN', 4, 1),
('component_selector_multi_branch', '示例：条件选择器多分支', '组件教学 / 多分支路由 示例，展示 SELECTOR,IN_APP_NOTIFY 的配置和组合方式。', '多分支路由', '{"nodes":[{"id":"start","type":"START","name":"开始","category":"流程控制","x":400,"y":0,"config":{"nextNodeId":"selector"},"bizConfig":{"nextNodeId":"selector"}},{"id":"selector","type":"SELECTOR","name":"按用户分层选择","category":"逻辑分支","x":400,"y":160,"config":{"branches":[{"label":"高价值","rules":[{"field":"score","operator":"GT","value":"80"}],"nextNodeId":"notify_a"},{"label":"普通","rules":[{"field":"score","operator":"GTE","value":"40"}],"nextNodeId":"notify_b"}],"elseNodeId":"notify_c"},"bizConfig":{"branches":[{"label":"高价值","rules":[{"field":"score","operator":"GT","value":"80"}],"nextNodeId":"notify_a"},{"label":"普通","rules":[{"field":"score","operator":"GTE","value":"40"}],"nextNodeId":"notify_b"}],"elseNodeId":"notify_c"}},{"id":"notify_a","type":"IN_APP_NOTIFY","name":"高价值消息","category":"用户触达","x":120,"y":340,"config":{"messageCodeKey":"vip_message","nextNodeId":"end"},"bizConfig":{"messageCodeKey":"vip_message","nextNodeId":"end"}},{"id":"notify_b","type":"IN_APP_NOTIFY","name":"普通消息","category":"用户触达","x":400,"y":340,"config":{"messageCodeKey":"normal_message","nextNodeId":"end"},"bizConfig":{"messageCodeKey":"normal_message","nextNodeId":"end"}},{"id":"notify_c","type":"IN_APP_NOTIFY","name":"兜底消息","category":"用户触达","x":680,"y":340,"config":{"messageCodeKey":"fallback_message","nextNodeId":"end"},"bizConfig":{"messageCodeKey":"fallback_message","nextNodeId":"end"}},{"id":"end","type":"END","name":"结束","category":"流程控制","x":400,"y":520,"config":{},"bizConfig":{}}]}', NULL, 1, 0, 'example-seed', NOW(), '组件教学', '多分支路由', '进阶', 'SELECTOR,IN_APP_NOTIFY', 5, 1),
