('component_hub_wait_all', '示例：集线器等待并行完成', '组件教学 / 并行等待 示例，展示 HUB,API_CALL 的配置和组合方式。', '并行等待', '{"nodes":[{"id":"start","type":"START","name":"开始","category":"流程控制","x":400,"y":0,"config":{"nextNodeId":"api_a"},"bizConfig":{"nextNodeId":"api_a"}},{"id":"api_a","type":"API_CALL","name":"并行任务 A","category":"其他","x":180,"y":160,"config":{"apiKey":"query_user_info","nextNodeId":"hub"},"bizConfig":{"apiKey":"query_user_info","nextNodeId":"hub"}},{"id":"api_b","type":"API_CALL","name":"并行任务 B","category":"其他","x":620,"y":160,"config":{"apiKey":"query_user_info","nextNodeId":"hub"},"bizConfig":{"apiKey":"query_user_info","nextNodeId":"hub"}},{"id":"hub","type":"HUB","name":"等待并行完成","category":"逻辑分支","x":400,"y":340,"config":{"timeout":600,"nextNodeId":"send_mq"},"bizConfig":{"timeout":600,"nextNodeId":"send_mq"}},{"id":"send_mq","type":"SEND_MQ","name":"同步完成结果","category":"其他","x":400,"y":500,"config":{"messageCodeKey":"hub_done","nextNodeId":"end"},"bizConfig":{"messageCodeKey":"hub_done","nextNodeId":"end"}},{"id":"end","type":"END","name":"结束","category":"流程控制","x":400,"y":660,"config":{},"bizConfig":{}}]}', NULL, 1, 0, 'example-seed', NOW(), '组件教学', '并行等待', '复杂', 'HUB,API_CALL', 8, 1),
